import json
from kafka import KafkaConsumer, KafkaProducer

def validate_input(record):
    try:
        json_data = json.loads(record)
        if isinstance(json_data, dict):
            return json_data
        else:
            raise ValueError("Input is not a valid JSON object.")
    except json.JSONDecodeError:
        raise ValueError("Input is not valid JSON.")

def count_maps(json_data):
    return sum(1 for value in json_data.values() if isinstance(value, dict))

def solve(input_topic, output_topic, kafka_broker):
    consumer = KafkaConsumer(input_topic, bootstrap_servers=kafka_broker)
    producer = KafkaProducer(bootstrap_servers=kafka_broker)

    for message in consumer:
        record = message.value.decode('utf-8')
        try:
            json_data = validate_input(record)
            map_count = count_maps(json_data)
            producer.send(output_topic, str(map_count).encode('utf-8'))
        except ValueError as e:
            print(f"Error processing record: {e}")

    consumer.close()
    producer.close()
